section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/spatial-computing-overview.json",
  "title": "Spatial Computing Overview",
  "type": "object",
  "required": [
    "artefact_id",
    "report_id",
    "platforms_covered",
    "terminology",
    "market_positioning",
    "constraints_table",
    "evidence",
    "last_reviewed",
    "owner",
    "status",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "report_id": {
      "type": "string",
      "description": "report_id",
      "minLength": 1
    },
    "platforms_covered": {
      "type": "array",
      "description": "platforms_covered (array)",
      "minItems": 1
    },
    "terminology": {
      "type": "string",
      "description": "terminology",
      "minLength": 1
    },
    "market_positioning": {
      "type": "string",
      "description": "market_positioning",
      "minLength": 1
    },
    "constraints_table": {
      "type": "string",
      "description": "constraints_table",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "last_reviewed": {
      "type": "string",
      "description": "last_reviewed",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
